{
  "mode": "method",
  "tests": [
    {
      "name": "list_challenges_copilot",
      "input": {},
      "output": [
        {"id": 1, "name": "Challenge 1", "type": "COPILOT"},
        {"id": 2, "name": "Challenge 2", "type": "COPILOT"}
      ],
      "notes": "Validates the retrieval of challenges for COPILOT type."
    },
    {
      "name": "create_challenge_admin",
      "input": {"name": "New Challenge", "type": "ADMIN"},
      "output": {"id": 3, "name": "New Challenge", "type": "ADMIN"},
      "notes": "Tests the creation of a new challenge by an ADMIN."
    },
    {
      "name": "get_challenge_statistics_valid",
      "input": {"challenge_id": 1},
      "output": {"id": 1, "statistics": {"submissions": 10, "winners": 2}},
      "notes": "Checks statistics retrieval for a valid challenge."
    },
    {
      "name": "get_challenge_statistics_invalid",
      "input": {"challenge_id": 999},
      "output": "Challenge not found",
      "notes": "Tests response for a non-existent challenge ID."
    },
    {
      "name": "post_challenge_notification",
      "input": {"challenge_id": 1, "message": "New update available"},
      "output": "Notification sent",
      "notes": "Validates sending a notification for a challenge."
    },
    {
      "name": "list_challenges_empty",
      "input": {},
      "output": [],
      "notes": "Tests the case where no challenges exist."
    },
    {
      "name": "create_challenge_missing_fields",
      "input": {"type": "ADMIN"},
      "output": "Missing required fields",
      "notes": "Validates error handling for missing required fields during challenge creation."
    },
    {
      "name": "get_challenge_statistics_edge_case",
      "input": {"challenge_id": 0},
      "output": "Invalid challenge ID",
      "notes": "Tests response for an edge case with an invalid challenge ID."
    }
  ],
  "assumptions": "All challenges are stored in a Postgres database using Prisma ORM.",
  "notes": "Ensure that the database is seeded with initial data for testing."
}
